#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";serial=;target=;profile=KCalc;probe_apk=;adb_path=;timeout=30;while (($#));do case "$1" in --serial)serial="${2:?}";shift 2;;--target-package)target="${2:?}";shift 2;;--profile)profile="${2:?}";shift 2;;--probe-apk)probe_apk="${2:?}";shift 2;;--adb-path)adb_path="${2:?}";shift 2;;--timeout-seconds)timeout="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;[[ -n "$serial" && -n "$target" ]] || archphene_die '--serial and --target-package are required';archphene_validate_choice "$profile" profile KCalc Mousepad;[[ -z "$adb_path" ]] || ARCHPHENE_ADB="$adb_path";archphene_test_init "$serial";if [[ -n "$probe_apk" ]];then archphene_adb_run install -r "$probe_apk" >/dev/null;fi;archphene_adb_run shell pm path "$target" >/dev/null;activity="$(archphene_launcher "$target")";archphene_adb_run shell am start -W -n "$activity" >/dev/null;archphene_wait_log 'mapped=true' "$timeout" 'ArchpheneInput:V AndroidRuntime:E *:S' >/dev/null;ui="$(archphene_capture_ui real-accessibility)";[[ "$ui" != *'FATAL EXCEPTION'* ]] || archphene_die 'target crashed';archphene_note "Real $profile accessibility passed on $serial for $target: normalized UI surface and semantic bridge startup verified."
